/**
 * Authenticate a user by ID and password.
 * Returns the user object (with role) or null.
 */
export function authenticateUser(id, password) {
  const user = USERS.find(
    (u) => u.id.toLowerCase() === id.trim().toLowerCase() && u.password === password.trim()
  );
  return user || null;
}
